-- 1. 將重複 email 的較新帳號（client 角色）設為 NULL（保留較早的 user 帳號）
UPDATE users SET email = NULL WHERE id = 7350058 AND email = 'garden.vc.tw@gmail.com';

-- 2. 刪除測試使用者帳號（test-client-* 的 email）
DELETE FROM users WHERE email LIKE 'test-client-%@example.com';

-- 3. 現在套用 unique constraint
ALTER TABLE users ADD CONSTRAINT users_email_unique UNIQUE (email);

-- 4. 驗證結果
SELECT id, name, email, role, createdAt FROM users ORDER BY email, createdAt;

